-- Phase 1j Stage 1 — create intel_stores_v2 and seed it from the current LCB
-- retail licensee list + 7 tribal rows. Shadow table, built alongside the
-- existing intel_stores. No modifications to intel_stores.
-- See audit/38-stage-1-fresh-import.md for verification + delta analysis.

-- ── 1. Table ────────────────────────────────────────────────────────────
CREATE TABLE intel_stores_v2 (LIKE intel_stores INCLUDING DEFAULTS INCLUDING IDENTITY);

-- Rewrite lcb_license_id from UUID-FK-to-lcb_licenses to plain TEXT holding
-- the LCB license number directly. v2 is anchored to the LCB number itself,
-- not to an intermediary lcb_licenses table.
ALTER TABLE intel_stores_v2 DROP COLUMN lcb_license_id;
ALTER TABLE intel_stores_v2 ADD  COLUMN lcb_license_id TEXT;

ALTER TABLE intel_stores_v2 ADD COLUMN ubi                        TEXT;
ALTER TABLE intel_stores_v2 ADD COLUMN license_status             TEXT;
ALTER TABLE intel_stores_v2 ADD COLUMN source_of_truth            TEXT;
ALTER TABLE intel_stores_v2 ADD COLUMN website_verified           BOOLEAN DEFAULT FALSE;
ALTER TABLE intel_stores_v2 ADD COLUMN website_association_source TEXT;
ALTER TABLE intel_stores_v2 ADD COLUMN v2_notes                   TEXT;

ALTER TABLE intel_stores_v2 ALTER COLUMN has_online_menu DROP NOT NULL;
ALTER TABLE intel_stores_v2 ALTER COLUMN total_products  DROP NOT NULL;
ALTER TABLE intel_stores_v2 ADD PRIMARY KEY (id);
CREATE UNIQUE INDEX idx_intel_stores_v2_license ON intel_stores_v2(lcb_license_id) WHERE lcb_license_id IS NOT NULL;
CREATE UNIQUE INDEX idx_intel_stores_v2_ubi     ON intel_stores_v2(ubi)            WHERE ubi IS NOT NULL;
CREATE        INDEX idx_intel_stores_v2_city    ON intel_stores_v2(city);
CREATE        INDEX idx_intel_stores_v2_status  ON intel_stores_v2(status);
CREATE        INDEX idx_intel_stores_v2_source  ON intel_stores_v2(source_of_truth);

-- ── 2. LCB main-sheet active retailers (source_of_truth = 'lcb_retail') ──
-- Expected: 458 rows

-- ── 3. LCB Social Equity active retailers (source_of_truth = 'lcb_social_equity') ──
-- Expected: 5 rows

-- ── 4. Tribal retailers (source_of_truth = 'tribal_manual') ──
-- Carried forward from existing intel_stores.  Sovereign, LCB-exempt.
-- v2_notes retains the original intel_stores.id so Stage 5 can re-attach menu data.
-- Expected: 7 rows

-- ── 5. Validation — post-insert sanity checks ──
DO $$
DECLARE
  total        INT;
  lcb_active   INT;
  se_active    INT;
  tribal_ct    INT;
  dup_license  INT;
  dup_ubi      INT;
BEGIN
  SELECT COUNT(*) INTO total FROM intel_stores_v2;
  SELECT COUNT(*) INTO lcb_active FROM intel_stores_v2 WHERE source_of_truth = 'lcb_retail';
  SELECT COUNT(*) INTO se_active  FROM intel_stores_v2 WHERE source_of_truth = 'lcb_social_equity';
  SELECT COUNT(*) INTO tribal_ct  FROM intel_stores_v2 WHERE source_of_truth = 'tribal_manual';
  SELECT COUNT(*) INTO dup_license FROM (SELECT lcb_license_id FROM intel_stores_v2 WHERE lcb_license_id IS NOT NULL GROUP BY 1 HAVING COUNT(*) > 1) x;
  SELECT COUNT(*) INTO dup_ubi     FROM (SELECT ubi FROM intel_stores_v2 WHERE ubi IS NOT NULL GROUP BY 1 HAVING COUNT(*) > 1) x;
  RAISE NOTICE 'intel_stores_v2 totals: total=%, lcb_retail=%, lcb_social_equity=%, tribal_manual=%, dup_license=%, dup_ubi=%',
    total, lcb_active, se_active, tribal_ct, dup_license, dup_ubi;
  IF total <> 470 THEN
    RAISE EXCEPTION 'Unexpected row count: got %, expected 470', total;
  END IF;
  IF dup_license > 0 OR dup_ubi > 0 THEN
    RAISE EXCEPTION 'Duplicate license (%)  or ubi (%) found', dup_license, dup_ubi;
  END IF;
END $$;
